4	import { Injectable, Logger, OnModuleDestroy, OnModuleInit } from '@nestjs/common';
5	import { Piscina } from 'piscina';
6	
7	import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
8	import { EnvConfigService } from '@modules/env-config/env-config.service';
9	
