11	
12	import { NODE_ENV } from '@constants/env-variables.constant';
13	
14	import { IProductColor } from '@interfaces/algolia-hits.interface';
15	
16	@Injectable()
17	export class ColorMatchWorkerService implements OnModuleInit, OnModuleDestroy {
18		private readonly logger = new Logger(ColorMatchWorkerService.name);
19		private pool!: Piscina;
20	
21		constructor(private readonly envConfigService: EnvConfigService) {}
22	
23		onModuleInit(): void {
24			const isDevelopment =
25				this.envConfigService.get<string>({ key: NODE_ENV }) === 'development';
26			let workerPath: string;
27	
28			if (isDevelopment) {
29				workerPath = path.join(
30					process.cwd(),
31					'src',
32					'modules',
33					'color-match-worker',
34					'color-match.worker.ts',
35				);
36			} else {
37				workerPath = path.resolve(__dirname, 'color-match.worker.js');
38			}
39	
40			const cpuCount = os.availableParallelism?.() ?? os.cpus().length;
41	
42			this.pool = new Piscina({
43				filename: workerPath,
44				minThreads: 1,
45				maxThreads: Math.max(1, cpuCount - 1),
46				idleTimeout: 30000,
47				...(isDevelopment && {
48					execArgv: [
49						'--require',
50						'ts-node/register',
51						'--require',
52						'tsconfig-paths/register',
53					],
54				}),
55			});
56	
57			this.logger.log(
58				`Color match worker pool initialized: workerPath=${workerPath}, minThreads=1, maxThreads=${Math.max(1, cpuCount - 1)}`,
59			);
60		}
61	
62		async onModuleDestroy(): Promise<void> {
63			if (this.pool) {
64				await this.pool.destroy();
65				this.logger.log('Color match worker pool destroyed');
66			}
67		}
68	
69		async findClosestColorId({
70			color,
71			palette,
72		}: {
73			color: IStyleColorBase | null;
74			palette: IProductColor[];
75		}): Promise<number> {
76			if (!color || !palette.some((item) => item.rbgs?.length)) {
77				this.logger.warn(
78					'[findClosestColorId]: No color or palette provided, defaulting to color ID 0',
79				);
80				return 0;
81			}
82	
83			const referenceColor = palette.find((item) => item.name === color.color_name);
84	
85			if (referenceColor) {
86				this.logger.debug(
87					`[findClosestColorId]: Exact color match found for "${color.color_name}", using color ID ${referenceColor.id}`,
88				);
89				return referenceColor.id;
90			}
91	
92			const selectedColorRGB = color.color_rgb;
93	
94			if (!selectedColorRGB || !palette.length) {
95				this.logger.warn(
96					'[findClosestColorId]: No selected color RGB or empty palette, defaulting to color ID 0',
97				);
98				return 0;
99			}
100	
101			const colorsHash = getColorRGBToIdHash({ colors: palette });
102	
103			const paletteColors = palette.reduce<{ R: number; G: number; B: number }[]>(
104				(acc, color) => {
105					if (color.rbgs?.[0]) {
106						acc.push(color.rbgs[0]);
107					}
108					return acc;
109				},
110				[],
111			);
112	
113			const closestColorId = (await this.pool.run({
114				selectedColorRGB: convertStringToRGB({ str: selectedColorRGB }),
115				paletteColors,
116				colorsHash,
117			})) as number;
118	
119			this.logger.debug(
120				`[findClosestColorId]: Closest color to "${color.color_name}" (RGB: ${selectedColorRGB}) is color ID ${closestColorId}. colorsHash: ${JSON.stringify(colorsHash)}, paletteColors: ${JSON.stringify(paletteColors)}`,
121			);
122	
123			return closestColorId;
124		}
125	}
