import { Test, TestingModule } from '@nestjs/testing';

import { ColorMatchWorkerService } from '@modules/color-match-worker/color-match-worker.service';
import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';

import { IProductColor } from '@interfaces/algolia-hits.interface';

jest.mock('piscina', () => ({
	Piscina: jest.fn().mockImplementation(() => ({
		run: jest.fn().mockResolvedValue(0),
		destroy: jest.fn().mockResolvedValue(undefined),
	})),
}));

const mockPalette: IProductColor[] = [
	{
		id: 1,
		name: 'Red',
		rbgs: [{ R: 255, G: 0, B: 0 }],
		image_url: 'https://example.com/color/1',
	},
	{
		id: 2,
		name: 'Green',
		rbgs: [{ R: 0, G: 255, B: 0 }],
		image_url: 'https://example.com/color/2',
	},
	{
		id: 3,
		name: 'Blue',
		rbgs: [{ R: 0, G: 0, B: 255 }],
		image_url: 'https://example.com/color/3',
	},
];

const createMockColor = (overrides: Partial<IStyleColorBase> = {}): IStyleColorBase => ({
	_id: '999',
	style_id: 999,
	color_id: 999,
	color_name: 'Red',
	color_rgb: 'R:200,G:0,B:0',
	image_url: null,
	is_active: true,
	created_at: new Date(),
	updated_at: new Date(),
	deleted_at: null,
	...overrides,
});

describe('ColorMatchWorkerService', () => {
	let service: ColorMatchWorkerService;
	let mockPoolRun: jest.Mock;

	beforeEach(async () => {
		const module: TestingModule = await Test.createTestingModule({
			providers: [
				ColorMatchWorkerService,
				{
					provide: EnvConfigService,
					useValue: { get: jest.fn().mockReturnValue('test') },
				},
			],
		}).compile();

		service = module.get<ColorMatchWorkerService>(ColorMatchWorkerService);
		await module.init();

		mockPoolRun = (service as any).pool.run as jest.Mock;
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	describe('onModuleInit', () => {
		it('should use .ts worker path in development mode', async () => {
			const Piscina = jest.requireMock('piscina').Piscina;
			Piscina.mockClear();

			const devModule: TestingModule = await Test.createTestingModule({
				providers: [
					ColorMatchWorkerService,
					{
						provide: EnvConfigService,
						useValue: { get: jest.fn().mockReturnValue('development') },
					},
				],
			}).compile();

			await devModule.init();

			expect(Piscina).toHaveBeenCalledWith(
				expect.objectContaining({
					filename: expect.stringContaining('color-match.worker.ts'),
					execArgv: expect.arrayContaining(['--require', 'ts-node/register']),
				}),
			);
		});

		it('should use os.availableParallelism() for thread count', async () => {
			const Piscina = jest.requireMock('piscina').Piscina;
			Piscina.mockClear();

			const testModule: TestingModule = await Test.createTestingModule({
				providers: [
					ColorMatchWorkerService,
					{
						provide: EnvConfigService,
						useValue: { get: jest.fn().mockReturnValue('test') },
					},
				],
			}).compile();

			await testModule.init();

			const cpuCount = os.availableParallelism();

			expect(Piscina).toHaveBeenCalledWith(
				expect.objectContaining({
					maxThreads: Math.max(1, cpuCount - 1),
				}),
			);
		});
	});

	describe('onModuleDestroy', () => {
		it('should destroy the pool', async () => {
			const mockDestroy = (service as any).pool.destroy as jest.Mock;

			await service.onModuleDestroy();

			expect(mockDestroy).toHaveBeenCalled();
		});

		it('should always call pool.destroy since pool is initialized in onModuleInit', async () => {
			const mockDestroy = (service as any).pool.destroy as jest.Mock;

			await service.onModuleDestroy();

			expect(mockDestroy).toHaveBeenCalledTimes(1);
		});
	});

	describe('findClosestColorId', () => {
		it('should return 0 when no color provided', async () => {
			const result = await service.findClosestColorId({
				color: null,
				palette: mockPalette,
			});

			expect(result).toBe(0);
			expect(mockPoolRun).not.toHaveBeenCalled();
		});

		it('should return 0 when palette has no RGB values', async () => {
			const color = createMockColor();
			const palette: IProductColor[] = [{ id: 1, name: 'NoRGB', rbgs: [] }];

			const result = await service.findClosestColorId({ color, palette });

			expect(result).toBe(0);
			expect(mockPoolRun).not.toHaveBeenCalled();
		});

		it('should return exact match ID without calling worker', async () => {
			const color = createMockColor({ color_name: 'Red' });

			const result = await service.findClosestColorId({ color, palette: mockPalette });

			expect(result).toBe(1);
			expect(mockPoolRun).not.toHaveBeenCalled();
		});

		it('should return 0 when no color RGB and no exact name match', async () => {
			const color = createMockColor({ color_name: 'Unknown', color_rgb: '' });

			const result = await service.findClosestColorId({ color, palette: mockPalette });

			expect(result).toBe(0);
			expect(mockPoolRun).not.toHaveBeenCalled();
		});

		it('should delegate to worker pool when no exact match', async () => {
			const color = createMockColor({
				color_name: 'DarkRed',
				color_rgb: 'R:139,G:0,B:0',
			});
			mockPoolRun.mockResolvedValue(1);

			const result = await service.findClosestColorId({ color, palette: mockPalette });

			expect(result).toBe(1);
			expect(mockPoolRun).toHaveBeenCalledWith({
				selectedColorRGB: { R: 139, G: 0, B: 0 },
				paletteColors: [
