					{ R: 0, G: 255, B: 0 },
					{ R: 0, G: 0, B: 255 },
				],
				colorsHash: {
					'R:255,G:0,B:0': 1,
					'R:0,G:255,B:0': 2,
					'R:0,G:0,B:255': 3,
				},
			});
		});

		it('should handle palette with missing RGB values', async () => {
