				color_name: 'Purple',
				color_rgb: 'R:128,G:0,B:128',
			});
			const paletteWithMissing: IProductColor[] = [
				...mockPalette,
				{ id: 7, name: 'Invalid', rbgs: [] },
			];
			mockPoolRun.mockResolvedValue(3);

			const result = await service.findClosestColorId({
				color,
				palette: paletteWithMissing,
			});

			expect(result).toBe(3);
			expect(mockPoolRun).toHaveBeenCalled();
		});

		it('should return 0 when empty palette and no exact name match', async () => {
			const color = createMockColor({ color_name: 'Unknown', color_rgb: 'R:0,G:0,B:0' });

			const result = await service.findClosestColorId({ color, palette: [] });

			expect(result).toBe(0);
		});
	});
